            ),
            'oadp-velero-restic-restore-helper': self._make_gitdata_entry(
                'oadp-velero-restic-restore-helper'
            ),
        }

        result = self.scanner._find_images_with_disabled_dependencies()
        self.assertEqual(result, set())

